import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

const 核心属性 = z.object({
  演绎力: z.coerce.number().prefault(10),
  观察力: z.coerce.number().prefault(10),
  沟通力: z.coerce.number().prefault(10),
  应变力: z.coerce.number().prefault(10),
  抗压性: z.coerce.number().prefault(10),
  情报力: z.coerce.number().prefault(10),
  气运值: z.coerce.number().prefault(10)
}).prefault({
  演绎力: 10,
  观察力: 10,
  沟通力: 10,
  应变力: 10,
  抗压性: 10,
  情报力: 10,
  气运值: 10
});

const 伙伴状态 = z.object({
  羁绊等级: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
  精神状态: z.enum(['稳定', '焦虑', '创伤后应激', '成瘾状态', '疯狂', '崩溃', '死亡']).prefault('稳定'),
  生命值: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(100),
  专属特质: z.boolean().prefault(false)
}).prefault({
  羁绊等级: 0,
  精神状态: '稳定',
  生命值: 100,
  专属特质: false
});

export const Schema = z.object({
  世界层: z.object({
    当前日期: z.string().prefault('1996年12月25日'),
    当前时间: z.string().prefault('00:00'),
    时间线节点: z.enum([
      '第一季开篇',
      '第一季结局',
      '第二季结局',
      '第三季',
      '第四季',
      '隐藏终局'
    ]).prefault('第一季开篇'),
    游戏难度: z.string().prefault(''),
    博弈本质: z.string().prefault(''),
    世界现状: z.string().prefault('')
  }).prefault({
    当前日期: '1996年12月25日',
    当前时间: '00:00',
    时间线节点: '第一季开篇',
    游戏难度: '',
    博弈本质: '',
    世界现状: ''
  }),

  阵营状态层: z.object({
    线索权重: z.coerce.number().prefault(0),
    警队话语权: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    情报覆盖度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    信任总值: z.coerce.number().prefault(0),
    演绎等级: z.enum(['入门级', '专业级', '大师级', '殿堂级']).prefault('入门级'),
    警队公信力: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(50),
    团队士气: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(50),
    探案准则: z.object({
      执法边界: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      信息管控: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      博弈底线: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      能力使用: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0)
    }).prefault({
      执法边界: 0,
      信息管控: 0,
      博弈底线: 0,
      能力使用: 0
    }),
    宏观属性: z.object({
      棋局掌控力: z.coerce.number().prefault(0),
      安保防护等级: z.coerce.number().prefault(0),
      行动隐蔽度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(50)
    }).prefault({
      棋局掌控力: 0,
      安保防护等级: 0,
      行动隐蔽度: 50
    })
  }).prefault({
    线索权重: 0,
    警队话语权: 0,
    情报覆盖度: 0,
    信任总值: 0,
    演绎等级: '入门级',
    警队公信力: 50,
    团队士气: 50,
    探案准则: {
      执法边界: 0,
      信息管控: 0,
      博弈底线: 0,
      能力使用: 0
    },
    宏观属性: {
      棋局掌控力: 0,
      安保防护等级: 0,
      行动隐蔽度: 50
    }
  }),

  派系羁绊层: z.object({
    贝克街221B小队: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    苏格兰场重案组: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    大英政府: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    莫里亚蒂犯罪网络: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    谢林福特特殊监禁区: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    伦敦地下线人网络: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0)
  }).prefault({
    贝克街221B小队: 0,
    苏格兰场重案组: 0,
    大英政府: 0,
    莫里亚蒂犯罪网络: 0,
    谢林福特特殊监禁区: 0,
    伦敦地下线人网络: 0
  }),

  设施与道具层: z.object({
    设施等级: z.object({
      苏格兰场重案组办公室: z.coerce.number().transform(v => _.clamp(v, 1, 5)).prefault(1),
      贝克街221B演绎墙: z.coerce.number().transform(v => _.clamp(v, 0, 5)).prefault(0),
      巴茨医院法医实验室: z.coerce.number().transform(v => _.clamp(v, 0, 5)).prefault(0),
      伦敦监控与数字取证中心: z.coerce.number().transform(v => _.clamp(v, 0, 5)).prefault(0),
      伦敦安全屋网络: z.coerce.number().transform(v => _.clamp(v, 0, 5)).prefault(0),
      谢林福特监禁区会客室: z.boolean().prefault(false)
    }).prefault({
      苏格兰场重案组办公室: 1,
      贝克街221B演绎墙: 0,
      巴茨医院法医实验室: 0,
      伦敦监控与数字取证中心: 0,
      伦敦安全屋网络: 0,
      谢林福特监禁区会客室: false
    }),
    仓库: z.record(z.string().describe('物品键名'), z.union([
      z.boolean(),
      z.object({
        类型: z.string().prefault('普通道具'),
        数量: z.coerce.number().prefault(1)
      }).prefault({
        类型: '普通道具',
        数量: 1
      })
    ])).prefault({})
  }).prefault({
    设施等级: {
      苏格兰场重案组办公室: 1,
      贝克街221B演绎墙: 0,
      巴茨医院法医实验室: 0,
      伦敦监控与数字取证中心: 0,
      伦敦安全屋网络: 0,
      谢林福特监禁区会客室: false
    },
    仓库: { 穿越者的剧情笔记: true }
  }),

  玩家状态: z.object({
    AP: z.coerce.number().transform(v => _.clamp(v, 0, 999)).prefault(100),
    AP上限: z.coerce.number().transform(v => _.clamp(v, 1, 999)).prefault(100),
    HP: z.coerce.number().transform(v => _.clamp(v, 0, 999)).prefault(100),
    HP上限: z.coerce.number().transform(v => _.clamp(v, 1, 999)).prefault(100),
    属性: 核心属性,
    超能力层级: z.coerce.number().transform(v => _.clamp(v, 0, 6)).prefault(0),
    特质: z.record(z.string().describe('特质名称'), z.any()).prefault({}),
    次元商城已购: z.record(z.string(), z.coerce.number()).prefault({})
  }).passthrough().prefault({
    AP: 100,
    AP上限: 100,
    HP: 100,
    HP上限: 100,
    属性: {
      演绎力: 10,
      观察力: 10,
      沟通力: 10,
      应变力: 10,
      抗压性: 10,
      情报力: 10,
      气运值: 10
    },
    超能力层级: 0,
    特质: {},
    次元商城已购: {}
  }),

  羁绊伙伴: z.object({
    夏洛克_福尔摩斯: 伙伴状态.prefault({羁绊等级: 20, 精神状态: '稳定', 生命值: 100, 专属特质: false}),
    约翰_H_华生: 伙伴状态.prefault({羁绊等级: 50, 精神状态: '稳定', 生命值: 100, 专属特质: false}),
    格雷格_雷斯垂德: 伙伴状态.prefault({羁绊等级: 60, 精神状态: '稳定', 生命值: 100, 专属特质: false}),
    欧洛丝_福尔摩斯: 伙伴状态.prefault({羁绊等级: 0, 精神状态: '稳定', 生命值: 100, 专属特质: false})
  }).prefault({
    夏洛克_福尔摩斯: {羁绊等级: 20, 精神状态: '稳定', 生命值: 100, 专属特质: false},
    约翰_H_华生: {羁绊等级: 50, 精神状态: '稳定', 生命值: 100, 专属特质: false},
    格雷格_雷斯垂德: {羁绊等级: 60, 精神状态: '稳定', 生命值: 100, 专属特质: false},
    欧洛丝_福尔摩斯: {羁绊等级: 0, 精神状态: '稳定', 生命值: 100, 专属特质: false}
  }),

  次元商城: z.object({
    扩展奇物: z.array(z.any()).prefault([])
  }).prefault({ 扩展奇物: [] }),

  游戏状态: z.record(z.string(), z.union([z.string(), z.number(), z.boolean()])).prefault({})
}).prefault({
  世界层: {当前日期: '1996年12月25日', 当前时间: '00:00', 时间线节点: '第一季开篇', 游戏难度: '', 博弈本质: '', 世界现状: ''},
  阵营状态层: {线索权重: 0, 警队话语权: 0, 情报覆盖度: 0, 信任总值: 0, 演绎等级: '入门级', 警队公信力: 50, 团队士气: 50, 探案准则: {执法边界: 0, 信息管控: 0, 博弈底线: 0, 能力使用: 0}, 宏观属性: {棋局掌控力: 0, 安保防护等级: 0, 行动隐蔽度: 50}},
  派系羁绊层: {贝克街221B小队: 0, 苏格兰场重案组: 0, 大英政府: 0, 莫里亚蒂犯罪网络: 0, 谢林福特特殊监禁区: 0, 伦敦地下线人网络: 0},
  设施与道具层: {设施等级: {苏格兰场重案组办公室: 1, 贝克街221B演绎墙: 0, 巴茨医院法医实验室: 0, 伦敦监控与数字取证中心: 0, 伦敦安全屋网络: 0, 谢林福特监禁区会客室: false}, 仓库: { 穿越者的剧情笔记: true }},
  玩家状态: {AP: 100, AP上限: 100, HP: 100, HP上限: 100, 属性: {演绎力: 10, 观察力: 10, 沟通力: 10, 应变力: 10, 抗压性: 10, 情报力: 10, 气运值: 10}, 超能力层级: 0, 特质: {}, 次元商城已购: {}},
  羁绊伙伴: {夏洛克_福尔摩斯: {羁绊等级: 20, 精神状态: '稳定', 生命值: 100, 专属特质: false}, 约翰_H_华生: {羁绊等级: 50, 精神状态: '稳定', 生命值: 100, 专属特质: false}, 格雷格_雷斯垂德: {羁绊等级: 60, 精神状态: '稳定', 生命值: 100, 专属特质: false}, 欧洛丝_福尔摩斯: {羁绊等级: 0, 精神状态: '稳定', 生命值: 100, 专属特质: false}},
  次元商城: { 扩展奇物: [] },
  游戏状态: {}
});

$(() => {
  registerMvuSchema(Schema);
})
